  ('disabled-64311456-moex-00305', 'disabled-64311456', 'disabled-64311456-moex-111-d1a761c9', 'sub-disabled-64311456-04', NULL, 'single_choice', '有關訴願法之敘述，下列何者錯誤？', '["地方自治團體、法人、非法人團體應由其代表人或管理人為訴願行為", "無訴願能力人應由其委託代理人代為訴願行為", "能獨立以法律行為負義務者，有訴願能力", "自然人、法人、非法人團體或其他受行政處分之相對人及利害關係人得 提起訴願"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:41+00:00", "source_pdf_sha1": "d46b18cb445c", "answer_pdf_sha1": "e205588da29c", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "402", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "社會行政"}'::jsonb, NULL),
